// Specification Generation
// Produces functional/non-functional requirements and API contracts.
// In production, this node would be replaced with an LLM call.
const { projectId, stageKey, executionId, subStage, context } = $input.first().json.body;

const specification = {
  functionalRequirements: [
    {
      id: "FR-001",
      title: "User Authentication",
      description: "Users must be able to register, log in, and manage sessions via email/password or OAuth 2.0 providers",
      priority: "high"
    },
    {
      id: "FR-002",
      title: "Project Creation",
      description: "Operators must be able to create projects with a name, description, and initial configuration parameters",
      priority: "high"
    },
    {
      id: "FR-003",
      title: "Pipeline Execution",
      description: "The system must orchestrate multi-stage pipelines with sequential sub-stage progression and approval gates",
      priority: "high"
    },
    {
      id: "FR-004",
      title: "Artifact Storage",
      description: "Each pipeline stage must produce typed artifacts that persist across sessions and are queryable by project and stage",
      priority: "medium"
    },
    {
      id: "FR-005",
      title: "Real-time Updates",
      description: "The dashboard must receive live updates via SSE when pipeline state changes or artifacts are produced",
      priority: "medium"
    }
  ],
  nonFunctionalRequirements: [
    {
      category: "Performance",
      requirement: "API response time under 200ms for read operations at p95",
      metric: "p95 latency ≤ 200ms"
    },
    {
      category: "Availability",
      requirement: "System uptime of 99.5% measured monthly",
      metric: "uptime ≥ 99.5%"
    },
    {
      category: "Scalability",
      requirement: "Support 100 concurrent pipeline executions without degradation",
      metric: "100 concurrent pipelines, <5% latency increase"
    },
    {
      category: "Security",
      requirement: "All API endpoints require authentication; secrets never logged",
      metric: "Zero secret leaks in logs, 100% endpoint auth coverage"
    }
  ],
  apiContracts: [
    {
      endpoint: "/api/pipeline/trigger",
      method: "POST",
      description: "Trigger a pipeline stage execution. Body: { projectId, stageKey, subStage?, context? }. Returns 201 with executionId."
    },
    {
      endpoint: "/api/pipeline/callback",
      method: "POST",
      description: "Receive n8n workflow results. Body: { executionId, projectId, stageKey, result, resumeUrl?, subStage? }. Returns artifact ID."
    },
    {
      endpoint: "/api/pipeline/approve",
      method: "POST",
      description: "Approve or reject a stage. Body: { projectId, stageKey, decision }. May auto-trigger next stage."
    },
    {
      endpoint: "/api/pipeline/status/:projectId",
      method: "GET",
      description: "Get per-stage execution state for a project. Returns stages map with status, subStage, timestamps."
    },
    {
      endpoint: "/api/artifacts/project/:projectId/stage/:stageKey",
      method: "GET",
      description: "List all artifacts for a project and stage. Returns array of { id, type, content, metadata }."
    }
  ],
  recommendation: "The specification covers the core MVP scope. Defer advanced features (RBAC, audit logging, multi-tenant isolation) to post-launch iterations. Prioritize pipeline orchestration reliability over feature breadth."
};

return {
  json: {
    projectId,
    stageKey,
    executionId,
    subStage: subStage || 'specification',
    specificationResult: specification
  }
};
